    def __init__(self, session_key, logger: logging.Logger, api_host='localhost', api_port=8089):
        self.session_key = session_key
        self.api_host = api_host
        self.api_port = api_port
        self.presentation = None

        feature = 'slides'
        
        # Define paths
        current_dir = os.path.dirname(os.path.abspath(__file__))
        resource_path = current_dir  # Using current_dir as resource_path
        logger.info(resource_path)
        splunk_home = "/opt/splunk"  # Replace with your SPLUNK_HOME path if different
        # Since we're using an inline CA certificate, no need to specify ca_cert_path
        # Ensure that the inline CA certificate in LicenseManager is correct
        
        # Ensure resource_path exists
        if not os.path.isdir(resource_path):
            logger.error(f"Resource path does not exist: {resource_path}")
            return

        # Initialize LicenseManager
        try:
            license_manager = LicenseManager(
                resource_path=resource_path,
                logger=logger
            )
        except LicenseError as le:
            logger.error(f"Initialization failed: {str(le)}")
            return

        try:
            # Verify the license and get the result and license info
            logger.info("Verifying license...")
            is_valid, license_info = license_manager.verify_license(feature)
            
            # Log the license validity
            logger.info(f"License valid: {'Yes' if is_valid else 'No'}")
            
            # Log the license information
            print("\n--- License Information ---")
            print(f"License Status   : {license_info['licensestatus']}")
            print(f"Licensed to      : {license_info['cn']}")
            print(f"Licensed feature : {license_info.get('features')}")
            print(f"Install Date     : {license_info.get('installdate')}")
            print(f"Valid Until      : {license_info.get('validtill')}")
            print(f"Trial License    : {license_info.get('triallicense')}")
            print("---------------------------\n")

            self.is_valid = is_valid #license_info.get('triallicense')
            
            # Final assessment
            if is_valid:
                logger.info(f"License is valid and includes the '{feature}' feature.")
            else:
                logger.warning(f"License is either invalid or does not include the '{feature}' feature.")
        
        except LicenseError as le:
            logger.error(f"License verification failed: {str(le)}")
        except Exception as e:
            logger.error(f"An unexpected error occurred: {str(e)}")

    def pixels_to_emu(self, pixels):
        return int(pixels * 914400 / 96)

    def is_background_or_black(self, pixel, bg_color, bg_tolerance=10, black_tolerance=30):
        is_bg = all(abs(pixel[i] - bg_color[i]) <= bg_tolerance for i in range(3))
        is_blackish = all(pixel[i] <= black_tolerance for i in range(3))
        return is_bg or is_blackish

    def find_content_bounding_box(self, image, bg_color, bg_tolerance=10, black_tolerance=30):
        width, height = image.size
        left, top, right, bottom = width, height, 0, 0

        for y in range(height):
            if not self.is_background_or_black(image.getpixel((4, y)), bg_color, bg_tolerance, black_tolerance):
                top = y
                break

        for y in range(height - 1, top - 1, -1):
            for x in range(width):
                if not self.is_background_or_black(image.getpixel((x, y)), bg_color, bg_tolerance, black_tolerance):
                    bottom = y
                    break
            if bottom > top:
                break

        for x in range(width):
            for y in range(top, bottom + 1):
                if not self.is_background_or_black(image.getpixel((x, y)), bg_color, bg_tolerance, black_tolerance):
                    left = x
                    break
            if left < width:
                break

        for x in range(width - 1, left - 1, -1):
            for y in range(top, bottom + 1):
                if not self.is_background_or_black(image.getpixel((x, y)), bg_color, bg_tolerance, black_tolerance):
                    right = x
                    break
            if right > left:
                break

        return (left, top, right + 1, bottom + 1)

    def merge_images_from_bytesio(self, image1_bytes, image2_bytes):
        print("merge images", sys.stderr)
        # Open the first image from BytesIO - patch, is already bytesio
        #image1 = Image.open(BytesIO(image1_bytes))
        image1 = Image.open(image1_bytes)

        # Open the second image from BytesIO
        image2 = Image.open(BytesIO(image2_bytes))

        # Ensure both images have the same mode (e.g., RGBA for transparency support)
        if image1.mode != 'RGBA':
            image1 = image1.convert('RGBA')
        if image2.mode != 'RGBA':
            image2 = image2.convert('RGBA')

        # Create a new image with the same size as the first image
        merged_image = Image.new('RGBA', image1.size)

        # Paste the first image onto the new image
        merged_image.paste(image1, (0, 0))

        # Paste the second image on top of the first image
        # The mask parameter ensures that transparency is respected
        merged_image.paste(image2, (0, 0), mask=image2)

        # Save the merged image to a BytesIO object
        output = BytesIO()
        merged_image.save(output, format="PNG")
        output.seek(0)

        return output

