    def export_dashboard(self, dashboard_item):
        if '/' in dashboard_item:
            namespace, dashboard_name = dashboard_item.split('/', 1)
        else:
            namespace = None
            dashboard_name = dashboard_item

        url = f"https://{self.api_host}:{self.api_port}/services/pdfgen/render"
        
        data = {
            "type": "png",
            "input-dashboard": dashboard_name
        }
        
        if namespace:
            data["namespace"] = namespace

        headers = {
            "Authorization": f"Splunk {self.session_key}",
            "Content-Type": "application/x-www-form-urlencoded"
        }
        r = requests.post(url, data=data, headers=headers, verify=False) #requests.post(url, headers=headers, verify=False)
        
        if r.status_code != 200:
            raise Exception(f"Failed to export dashboard {dashboard_name}, status code: {r.status_code}")

        filecontent = r.content
        image = Image.open(io.BytesIO(filecontent))

        bg_color = image.getpixel((0, 0))
        bbox = self.find_content_bounding_box(image, bg_color)
        cropped_image = image.crop(bbox)
        
        img_byte_arr = io.BytesIO()
        cropped_image.save(img_byte_arr, format='PNG')
        img_byte_arr.seek(0)

        return img_byte_arr

    def initialize_presentation(self, width_px=1920, height_px=1080):
        width_emu = self.pixels_to_emu(width_px)
        height_emu = self.pixels_to_emu(height_px)

        self.presentation = Presentation()
        self.presentation.slide_width = width_emu
        self.presentation.slide_height = height_emu

    def add_dashboard_slide(self, dashboard_name):
        if self.presentation is None:
            raise Exception("Presentation not initialized. Call initialize_presentation() first.")

        img_byte_arr = self.export_dashboard(dashboard_name)
        slide = self.presentation.slides.add_slide(self.presentation.slide_layouts[6])
        slide_width = self.presentation.slide_width
        slide_height = self.presentation.slide_height

        # Add watermark if not licensed
        if self.is_valid != True:
            slidecontent = self.add_watermark(img_byte_arr)
        else:
            slidecontent = img_byte_arr

        #pic = slide.shapes.add_picture(img_byte_arr, 0, 0, width=slide_width, height=slide_height)
        pic = slide.shapes.add_picture(slidecontent, 0, 0, width=slide_width, height=slide_height)

        # Add watermark
        #self.add_watermark(slide, slide_width, slide_height, "TRIAL VERSION")

    def get_presentation(self):
        if self.presentation is None:
            raise Exception("Presentation not initialized or empty.")

        pptx_byte_arr = io.BytesIO()
        self.presentation.save(pptx_byte_arr)
        pptx_byte_arr.seek(0)

        return pptx_byte_arr

